import { cn } from '@/utils/cn';
import { createThrottle } from '@/utils/helper';
import type { FactoryArg, InputMask } from 'imask';
import IMask from 'imask/holder';
import 'imask/masked/number';
import X from 'lucide-solid/icons/x';
import {
  Component,
  createEffect,
  createUniqueId,
  mergeProps,
  on,
  onCleanup,
  onMount,
  Show,
} from 'solid-js';
import type { InputNumberProps } from '../input.types';
import { DEFAULT_PROPS, inputTextVariants } from '../input.utils';

export const InputNumber: Component<InputNumberProps> = (p => {
  const id = createUniqueId();
  p = mergeProps({ ...DEFAULT_PROPS, id, offset: 1, wheel: false, keyboard: true }, p);
  let maskInstance: InputMask<FactoryArg> | undefined;
  let inputRef: HTMLInputElement | undefined;

  const options = () => ({
    min: Number.NEGATIVE_INFINITY,
    max: Number.POSITIVE_INFINITY,
    thousandsSeparator: '_',
    radix: '.',
    padFractionalZeros: false,
    normalizeZeros: true,
    ...p.maskOptions,
    mask: Number,
  });

  const focusInput = () => {
    inputRef?.focus();
  };

  let maskAcceptEvent: any = null;

  const updateValue = (delta: number) => {
    if (!maskInstance) return;

    const currentValue = maskInstance.unmaskedValue;
    const numericValue = currentValue === '' ? 0 : parseFloat(currentValue);
    let newValue = numericValue + delta;

    const min = p.maskOptions?.min ?? Number.NEGATIVE_INFINITY;
    const max = p.maskOptions?.max ?? Number.POSITIVE_INFINITY;
    newValue = Math.max(min, Math.min(max, newValue));

    maskInstance.unmaskedValue = String(newValue);
    maskInstance.updateValue();

    p.onChange?.(maskInstance.value, new Event('change'));
    p.onInput?.(maskInstance.value, new Event('input'));
    p.maskOptions?.onAccept?.(maskInstance.value, maskInstance.unmaskedValue);
  };

  const handleKeyDown = (e: KeyboardEvent) => {
    if (!p.keyboard) return;

    const offset = p.offset ?? 1;

    if (e.key === 'ArrowUp') {
      e.preventDefault();
      updateValue(offset);
    } else if (e.key === 'ArrowDown') {
      e.preventDefault();
      updateValue(-offset);
    }
  };

  const handleWheel = createThrottle((e: WheelEvent) => {
    if (!p.wheel) return;

    e.preventDefault();
    const offset = p.offset ?? 1;
    const delta = e.deltaY < 0 ? offset : -offset;
    updateValue(delta);
  }, 50);

  createEffect(
    on(
      () => options(),
      value => maskInstance && value && maskInstance.updateOptions(value),
      { defer: true },
    ),
  );

  onMount(() => {
    if (inputRef) {
      maskInstance = IMask(inputRef, options());

      maskAcceptEvent = (e: InputEvent) => {
        p.onChange?.(maskInstance?.value ?? '', e);
        p.maskOptions?.onAccept?.(maskInstance?.value, maskInstance?.unmaskedValue);
      };
      maskInstance.on('accept', maskAcceptEvent);
    }
  });

  onCleanup(function destroyNumberMask() {
    if (maskInstance) {
      maskAcceptEvent && maskInstance.off('accept', maskAcceptEvent);
      maskInstance.destroy();
    }
  });

  const handleClear = (e: MouseEvent) => {
    e.stopPropagation();
    if (maskInstance) {
      maskInstance.value = '';
      maskInstance.updateValue();
    } else if (inputRef) {
      inputRef.value = '';
    }
    p.onInput?.('', undefined as any);
    p.onChange?.('', undefined as any);
    inputRef?.focus();
  };

  return (
    <div
      tabIndex={-1}
      class={cn(
        'it01',
        inputTextVariants({ color: p.color, size: p.size, variant: p.variant }),
        p.class?.input,
        p.disabled && 'border-c5 pointer-events-none',
      )}
      onClick={focusInput}
    >
      {p.prefixIcon}
      <input
        id={p.id}
        ref={inputRef}
        type="text"
        data-type="number"
        value={p.value ?? ''}
        placeholder={p.placeholder}
        class="text-c2 grow"
        onBlur={e => p.onBlur?.(e.currentTarget.value, e)}
        onChange={e => p.onChange?.(e.currentTarget.value, e)}
        onInput={e => p.onInput?.(e.currentTarget.value, e)}
        onKeyDown={e => {
          if (e.key === 'Enter' || e.keyCode === 13) {
            e.preventDefault();
            p.onPressEnter?.(e.currentTarget.value, e);
          }
          handleKeyDown(e);
        }}
        onWheel={e => {
          if (p.wheel && document.activeElement === inputRef) {
            handleWheel(e);
          }
        }}
        disabled={p.disabled}
      />
      <Show when={p.allowClear || p.suffixIcon}>
        <div class="it05">
          {p.allowClear && (
            <div class="it03" onClick={handleClear}>
              <X class="m-auto size-2" />
            </div>
          )}
          {p.suffixIcon && <div class="it04">{p.suffixIcon}</div>}
        </div>
      </Show>
    </div>
  );
}) as Component<InputNumberProps>;
